const items = $input.all();

return items.map(item => {
  const contact = item.json.contact || {};
  const deals = contact.deals || [];
  const openDeals = deals.filter(d => d.status === 'open');
  const deal = openDeals.length > 0 ? openDeals[0] : (deals.length > 0 ? deals[0] : null);

  return {
    json: {
      deal_id: deal ? deal.id : null,
      has_deal: !!deal,
      executivo: $('Identificar Executivo').item.json.executivo_encontrado ? $('Identificar Executivo').item.json.executivo_encontrado.nome : $('When Executed by Another Workflow').item.json.executivo,
